args.query:
SELECT book_id, title, subtitle, author, categories, details, features
FROM books_info
WHERE (categories ILIKE '%Literature%' AND categories ILIKE '%Fiction%')
  AND (
    details ILIKE '%English%' OR details ILIKE '%Language%English%' OR features ILIKE '%English%'
  );

